select v_1 as "ps_partkey", v_2 as "value" from (select * from (select v_3 as v_1, sum(v_4 * v_5) as v_2 from (select * from (select * from (select "ps_partkey" as v_3, "ps_suppkey" as v_6, "ps_availqty" as v_5, "ps_supplycost" as v_4, "ps_comment" as v_7 from "partsupp") l inner join (select "s_suppkey" as v_8, "s_name" as v_9, "s_address" as v_10, "s_nationkey" as v_11, "s_phone" as v_12, "s_acctbal" as v_13, "s_comment" as v_14 from "supplier") r on v_6 = v_8) l inner join (select * from (select "n_nationkey" as v_15, "n_name" as v_16, "n_regionkey" as v_17, "n_comment" as v_18 from "nation") s where v_16 = 'GERMANY') r on v_11 = v_15) s group by 1) s where v_2 > (((select v_19 from (select sum(v_20 * v_21) as v_19 from (select * from (select * from (select "ps_partkey" as v_22, "ps_suppkey" as v_23, "ps_availqty" as v_21, "ps_supplycost" as v_20, "ps_comment" as v_24 from "partsupp") l inner join (select "s_suppkey" as v_25, "s_name" as v_26, "s_address" as v_27, "s_nationkey" as v_28, "s_phone" as v_29, "s_acctbal" as v_30, "s_comment" as v_31 from "supplier") r on v_23 = v_25) l inner join (select * from (select "n_nationkey" as v_32, "n_name" as v_33, "n_regionkey" as v_34, "n_comment" as v_35 from "nation") s where v_33 = 'GERMANY') r on v_28 = v_32) s) s)) * cast('0.0001' as decimal(5,4)))) s order by v_2 desc
